'use client'

/**
 * Memory Grid Advanced - Multiplayer Edition
 * Competitive advanced memory challenge
 */

import { useState, useEffect } from 'react'
import { GameMode, PlayerSide } from '@/lib/multiplayer/game-modes'
import { PlayerSetupManager } from '@/lib/multiplayer/player-setup'
import { SplitScreenEngine, PlayerGameState } from '@/lib/multiplayer/split-screen'
import { CompetitionEngine } from '@/lib/multiplayer/competition'
import { soundManager } from '@/lib/multiplayer/sounds'
import PlayerSetupLobby from '@/components/multiplayer/PlayerSetupLobby'
import SplitScreenLayout from '@/components/multiplayer/SplitScreenLayout'
import VictoryScreen from '@/components/multiplayer/VictoryScreen'
import Countdown from '@/components/multiplayer/Countdown'
import SmartboardControls from '@/components/multiplayer/SmartboardControls'
import { MemoryGridContent } from '@/lib/game-engine/content-pools/memory-grid-advanced'

enum GameState {
    SETUP = 'setup',
    COUNTDOWN = 'countdown',
    PLAYING = 'playing',
    VICTORY = 'victory'
}

interface MemoryQuestion {
    id: string
    content: { items: string[] }
    correctAnswer: string[]
    points: number
}

export default function MemoryGridAdvancedMultiplayer() {
    const [gameState, setGameState] = useState<GameState>(GameState.SETUP)
    const [setupManager, setSetupManager] = useState<PlayerSetupManager | null>(null)
    const [splitScreenEngine] = useState(() => new SplitScreenEngine())
    const [competitionEngine] = useState(() => new CompetitionEngine())

    const [playerOneState, setPlayerOneState] = useState<PlayerGameState | null>(null)
    const [playerTwoState, setPlayerTwoState] = useState<PlayerGameState | null>(null)
    const [showOvertake, setShowOvertake] = useState(false)

    const [smartboardMode, setSmartboardMode] = useState(false)
    const [touchOptimized, setTouchOptimized] = useState(true)
    const [soundEffects, setSoundEffects] = useState(true)
    const [showCompetitionBar, setShowCompetitionBar] = useState(true)

    useEffect(() => {
        soundManager.setEnabled(soundEffects)
    }, [soundEffects])

    const handleStartGame = (manager: PlayerSetupManager) => {
        setSetupManager(manager)
        setGameState(GameState.COUNTDOWN)
    }

    const handleCountdownComplete = () => {
        initializeMultiplayerGame()
        setGameState(GameState.PLAYING)
    }

    const initializeMultiplayerGame = () => {
        if (!setupManager) return

        const pool = MemoryGridContent.generateContentPool()
        const seed1 = Date.now()
        const seed2 = Date.now() + 1000

        const { playerOne: p1Questions, playerTwo: p2Questions } = splitScreenEngine.generateIndependentQuestions(
            pool,
            8,
            seed1,
            seed2
        )

        splitScreenEngine.initializeGame(p1Questions, p2Questions, 120)
        splitScreenEngine.startTimer(
            (timeLeft) => {
                const p1 = splitScreenEngine.getPlayerState(PlayerSide.LEFT)
                const p2 = splitScreenEngine.getPlayerState(PlayerSide.RIGHT)
                setPlayerOneState({ ...p1, timeRemaining: timeLeft })
                setPlayerTwoState({ ...p2, timeRemaining: timeLeft })
            },
            () => endGame()
        )

        setPlayerOneState(splitScreenEngine.getPlayerState(PlayerSide.LEFT))
        setPlayerTwoState(splitScreenEngine.getPlayerState(PlayerSide.RIGHT))
    }

    const handlePlayerAnswer = (side: PlayerSide, selected: string[]) => {
        const state = splitScreenEngine.getPlayerState(side)
        const currentQuestion = state.questions[state.currentIndex] as MemoryQuestion
        const isCorrect = selected.length === currentQuestion.correctAnswer.length

        splitScreenEngine.handleAnswer(side, isCorrect, isCorrect ? currentQuestion.points : 0)

        const p1State = splitScreenEngine.getPlayerState(PlayerSide.LEFT)
        const p2State = splitScreenEngine.getPlayerState(PlayerSide.RIGHT)

        const overtake = competitionEngine.updateScores(p1State.score, p2State.score)

        if (overtake) {
            setShowOvertake(true)
            soundManager.playOvertake()
            setTimeout(() => setShowOvertake(false), 2000)
        }

        if (isCorrect) {
            soundManager.playCorrect()
        } else {
            soundManager.playWrong()
        }

        setPlayerOneState(splitScreenEngine.getPlayerState(PlayerSide.LEFT))
        setPlayerTwoState(splitScreenEngine.getPlayerState(PlayerSide.RIGHT))

        if (splitScreenEngine.isGameOver()) {
            setTimeout(() => endGame(), 1000)
        }
    }

    const endGame = () => {
        splitScreenEngine.stopTimer()
        setGameState(GameState.VICTORY)
    }

    const handlePlayAgain = () => {
        competitionEngine.reset()
        splitScreenEngine.reset()
        setGameState(GameState.COUNTDOWN)
    }

    const handleSwitchSides = () => {
        setupManager?.switchSides()
        handlePlayAgain()
    }

    const handleNewPlayers = () => {
        competitionEngine.reset()
        splitScreenEngine.reset()
        setGameState(GameState.SETUP)
    }

    const handleBackToMenu = () => {
        window.location.href = '/dashboard/student/games'
    }

    const toggleFullscreen = () => {
        if (!document.fullscreenElement) {
            document.documentElement.requestFullscreen()
        } else {
            document.exitFullscreen()
        }
    }

    if (gameState === GameState.SETUP) {
        return <PlayerSetupLobby onStartGame={handleStartGame} gameName="Memory Grid Advanced Battle" />
    }

    if (gameState === GameState.COUNTDOWN) {
        return <Countdown onComplete={handleCountdownComplete} duration={3} />
    }

    if (gameState === GameState.VICTORY && setupManager && playerOneState && playerTwoState) {
        const winner = splitScreenEngine.getWinner()
        const stats = splitScreenEngine.getFinalStats()
        const { playerOne, playerTwo } = setupManager.getPlayers()

        return (
            <VictoryScreen
                winner={winner}
                playerOneName={playerOne.name}
                playerTwoName={playerTwo?.name || 'Player 2'}
                playerOneScore={stats.playerOne.score}
                playerTwoScore={stats.playerTwo.score}
                playerOneAccuracy={stats.playerOne.accuracy}
                playerTwoAccuracy={stats.playerTwo.accuracy}
                onPlayAgain={handlePlayAgain}
                onSwitchSides={handleSwitchSides}
                onNewPlayers={handleNewPlayers}
                onBackToMenu={handleBackToMenu}
            />
        )
    }

    if (gameState === GameState.PLAYING && setupManager && playerOneState && playerTwoState) {
        const { playerOne, playerTwo } = setupManager.getPlayers()

        return (
            <div className={smartboardMode ? 'smartboard-mode' : ''}>
                <SmartboardControls
                    smartboardMode={smartboardMode}
                    touchOptimized={touchOptimized}
                    soundEffects={soundEffects}
                    showCompetitionBar={showCompetitionBar}
                    onToggleSmartboard={setSmartboardMode}
                    onToggleTouch={setTouchOptimized}
                    onToggleSounds={setSoundEffects}
                    onToggleCompetitionBar={setShowCompetitionBar}
                    onToggleFullscreen={toggleFullscreen}
                />

                <SplitScreenLayout
                    playerOneName={playerOne.name}
                    playerTwoName={playerTwo?.name || 'Player 2'}
                    playerOneColor={playerOne.color}
                    playerTwoColor={playerTwo?.color || '#3B82F6'}
                    playerOneAvatar={playerOne.avatar}
                    playerTwoAvatar={playerTwo?.avatar || '🐯'}
                    playerOneScore={playerOneState.score}
                    playerTwoScore={playerTwoState.score}
                    showCompetitionBar={showCompetitionBar}
                    showOvertake={showOvertake}
                    smartboardMode={smartboardMode}
                    playerOneContent={
                        <MemoryGridPlayerSide
                            state={playerOneState}
                            onAnswer={(selected) => handlePlayerAnswer(PlayerSide.LEFT, selected)}
                            playerColor={playerOne.color}
                        />
                    }
                    playerTwoContent={
                        <MemoryGridPlayerSide
                            state={playerTwoState}
                            onAnswer={(selected) => handlePlayerAnswer(PlayerSide.RIGHT, selected)}
                            playerColor={playerTwo?.color || '#3B82F6'}
                        />
                    }
                />
            </div>
        )
    }

    return null
}

interface MemoryGridPlayerSideProps {
    state: PlayerGameState
    onAnswer: (selected: string[]) => void
    playerColor: string
}

function MemoryGridPlayerSide({ state, onAnswer, playerColor }: MemoryGridPlayerSideProps) {
    const [phase, setPhase] = useState<'memorize' | 'recall'>('memorize')
    const [selected, setSelected] = useState<string[]>([])

    const currentQuestion = state.questions[state.currentIndex] as MemoryQuestion
    if (!currentQuestion) return <div>Loading...</div>

    useEffect(() => {
        setPhase('memorize')
        setSelected([])
        const timer = setTimeout(() => setPhase('recall'), 3000)
        return () => clearTimeout(timer)
    }, [state.currentIndex])

    const handleSubmit = () => {
        onAnswer(selected)
        setSelected([])
    }

    const progress = ((state.currentIndex + 1) / state.questions.length) * 100

    return (
        <div className="space-y-6">
            <div className="h-3 bg-gray-200 rounded-full overflow-hidden">
                <div
                    className="h-full transition-all duration-300"
                    style={{ width: `${progress}%`, backgroundColor: playerColor }}
                />
            </div>

            <div className="flex justify-between items-center">
                <div className="text-center">
                    <div className="text-3xl font-black" style={{ color: playerColor }}>
                        {state.correct}/{state.questions.length}
                    </div>
                    <div className="text-sm text-gray-600">Correct</div>
                </div>

                <div className="text-center">
                    <div className="text-2xl font-bold" style={{ color: phase === 'memorize' ? '#F59E0B' : '#10B981' }}>
                        {phase === 'memorize' ? '👁️ MEMORIZE' : '🧠 RECALL'}
                    </div>
                </div>
            </div>

            {phase === 'memorize' && (
                <div className="bg-gradient-to-br from-amber-50 to-yellow-50 rounded-xl p-8 shadow-lg">
                    <div className="flex gap-4 justify-center text-6xl">
                        {currentQuestion.content.items.map((item, i) => (
                            <div key={i} className="animate-pulse">{item}</div>
                        ))}
                    </div>
                </div>
            )}

            {phase === 'recall' && (
                <div className="space-y-4">
                    <div className="bg-gradient-to-br from-green-50 to-emerald-50 rounded-xl p-6 shadow-lg">
                        <div className="text-lg mb-2">Selected Items:</div>
                        <div className="text-4xl min-h-[60px]">
                            {selected.length > 0 ? selected.join(' ') : '(none)'}
                        </div>
                    </div>

                    <button
                        onClick={handleSubmit}
                        className="w-full p-6 text-white text-xl font-bold rounded-xl touch-target"
                        style={{ backgroundColor: playerColor }}
                    >
                        Submit Answer
                    </button>
                </div>
            )}
        </div>
    )
}

'use client'

/**
 * Memory Matrix - Multiplayer Edition
 * Competitive memory pattern matching
 */

import { useState, useEffect } from 'react'
import { GameMode, PlayerSide } from '@/lib/multiplayer/game-modes'
import { PlayerSetupManager } from '@/lib/multiplayer/player-setup'
import { SplitScreenEngine, PlayerGameState } from '@/lib/multiplayer/split-screen'
import { CompetitionEngine } from '@/lib/multiplayer/competition'
import { soundManager } from '@/lib/multiplayer/sounds'
import PlayerSetupLobby from '@/components/multiplayer/PlayerSetupLobby'
import SplitScreenLayout from '@/components/multiplayer/SplitScreenLayout'
import VictoryScreen from '@/components/multiplayer/VictoryScreen'
import Countdown from '@/components/multiplayer/Countdown'
import SmartboardControls from '@/components/multiplayer/SmartboardControls'
import { MemoryMatrixContent, MemoryMatrixPattern } from '@/lib/game-engine/content-pools/memory-matrix'

enum GameState {
    SETUP = 'setup',
    COUNTDOWN = 'countdown',
    PLAYING = 'playing',
    VICTORY = 'victory'
}

export default function MemoryMatrixMultiplayer() {
    const [gameState, setGameState] = useState<GameState>(GameState.SETUP)
    const [setupManager, setSetupManager] = useState<PlayerSetupManager | null>(null)
    const [splitScreenEngine] = useState(() => new SplitScreenEngine())
    const [competitionEngine] = useState(() => new CompetitionEngine())

    const [playerOneState, setPlayerOneState] = useState<PlayerGameState | null>(null)
    const [playerTwoState, setPlayerTwoState] = useState<PlayerGameState | null>(null)
    const [showOvertake, setShowOvertake] = useState(false)

    const [smartboardMode, setSmartboardMode] = useState(false)
    const [touchOptimized, setTouchOptimized] = useState(true)
    const [soundEffects, setSoundEffects] = useState(true)
    const [showCompetitionBar, setShowCompetitionBar] = useState(true)

    useEffect(() => {
        soundManager.setEnabled(soundEffects)
    }, [soundEffects])

    const handleStartGame = (manager: PlayerSetupManager) => {
        setSetupManager(manager)
        setGameState(GameState.COUNTDOWN)
    }

    const handleCountdownComplete = () => {
        initializeMultiplayerGame()
        setGameState(GameState.PLAYING)
    }

    const initializeMultiplayerGame = () => {
        if (!setupManager) return

        const pool = MemoryMatrixContent.generateContentPool()
        const seed1 = Date.now()
        const seed2 = Date.now() + 1000

        const { playerOne: p1Questions, playerTwo: p2Questions } = splitScreenEngine.generateIndependentQuestions(
            pool,
            8,
            seed1,
            seed2
        )

        splitScreenEngine.initializeGame(p1Questions, p2Questions, 120)
        splitScreenEngine.startTimer(
            (timeLeft) => {
                const p1 = splitScreenEngine.getPlayerState(PlayerSide.LEFT)
                const p2 = splitScreenEngine.getPlayerState(PlayerSide.RIGHT)
                setPlayerOneState({ ...p1, timeRemaining: timeLeft })
                setPlayerTwoState({ ...p2, timeRemaining: timeLeft })
            },
            () => endGame()
        )

        setPlayerOneState(splitScreenEngine.getPlayerState(PlayerSide.LEFT))
        setPlayerTwoState(splitScreenEngine.getPlayerState(PlayerSide.RIGHT))
    }

    const handlePlayerAnswer = (side: PlayerSide, selectedCells: Set<number>) => {
        const state = splitScreenEngine.getPlayerState(side)
        const currentQuestion = state.questions[state.currentIndex] as MemoryMatrixPattern
        const correctPattern = new Set(currentQuestion.content.pattern)

        const correctSelections = Array.from(selectedCells).filter(cell => correctPattern.has(cell)).length
        const accuracy = correctSelections / correctPattern.size
        const isCorrect = accuracy === 1 && selectedCells.size === correctPattern.size

        const points = isCorrect ? currentQuestion.points : Math.floor(currentQuestion.points * accuracy)
        splitScreenEngine.handleAnswer(side, isCorrect, points)

        const p1State = splitScreenEngine.getPlayerState(PlayerSide.LEFT)
        const p2State = splitScreenEngine.getPlayerState(PlayerSide.RIGHT)

        const overtake = competitionEngine.updateScores(p1State.score, p2State.score)

        if (overtake) {
            setShowOvertake(true)
            soundManager.playOvertake()
            setTimeout(() => setShowOvertake(false), 2000)
        }

        if (isCorrect) {
            soundManager.playCorrect()
        } else if (accuracy >= 0.7) {
            soundManager.playCorrect()
        } else {
            soundManager.playWrong()
        }

        setPlayerOneState(splitScreenEngine.getPlayerState(PlayerSide.LEFT))
        setPlayerTwoState(splitScreenEngine.getPlayerState(PlayerSide.RIGHT))

        if (splitScreenEngine.isGameOver()) {
            setTimeout(() => endGame(), 1000)
        }
    }

    const endGame = () => {
        splitScreenEngine.stopTimer()
        setGameState(GameState.VICTORY)
    }

    const handlePlayAgain = () => {
        competitionEngine.reset()
        splitScreenEngine.reset()
        setGameState(GameState.COUNTDOWN)
    }

    const handleSwitchSides = () => {
        setupManager?.switchSides()
        handlePlayAgain()
    }

    const handleNewPlayers = () => {
        competitionEngine.reset()
        splitScreenEngine.reset()
        setGameState(GameState.SETUP)
    }

    const handleBackToMenu = () => {
        window.location.href = '/dashboard/student/games'
    }

    const toggleFullscreen = () => {
        if (!document.fullscreenElement) {
            document.documentElement.requestFullscreen()
        } else {
            document.exitFullscreen()
        }
    }

    if (gameState === GameState.SETUP) {
        return <PlayerSetupLobby onStartGame={handleStartGame} gameName="Memory Matrix Battle" />
    }

    if (gameState === GameState.COUNTDOWN) {
        return <Countdown onComplete={handleCountdownComplete} duration={3} />
    }

    if (gameState === GameState.VICTORY && setupManager && playerOneState && playerTwoState) {
        const winner = splitScreenEngine.getWinner()
        const stats = splitScreenEngine.getFinalStats()
        const { playerOne, playerTwo } = setupManager.getPlayers()

        return (
            <VictoryScreen
                winner={winner}
                playerOneName={playerOne.name}
                playerTwoName={playerTwo?.name || 'Player 2'}
                playerOneScore={stats.playerOne.score}
                playerTwoScore={stats.playerTwo.score}
                playerOneAccuracy={stats.playerOne.accuracy}
                playerTwoAccuracy={stats.playerTwo.accuracy}
                onPlayAgain={handlePlayAgain}
                onSwitchSides={handleSwitchSides}
                onNewPlayers={handleNewPlayers}
                onBackToMenu={handleBackToMenu}
            />
        )
    }

    if (gameState === GameState.PLAYING && setupManager && playerOneState && playerTwoState) {
        const { playerOne, playerTwo } = setupManager.getPlayers()

        return (
            <div className={smartboardMode ? 'smartboard-mode' : ''}>
                <SmartboardControls
                    smartboardMode={smartboardMode}
                    touchOptimized={touchOptimized}
                    soundEffects={soundEffects}
                    showCompetitionBar={showCompetitionBar}
                    onToggleSmartboard={setSmartboardMode}
                    onToggleTouch={setTouchOptimized}
                    onToggleSounds={setSoundEffects}
                    onToggleCompetitionBar={setShowCompetitionBar}
                    onToggleFullscreen={toggleFullscreen}
                />

                <SplitScreenLayout
                    playerOneName={playerOne.name}
                    playerTwoName={playerTwo?.name || 'Player 2'}
                    playerOneColor={playerOne.color}
                    playerTwoColor={playerTwo?.color || '#3B82F6'}
                    playerOneAvatar={playerOne.avatar}
                    playerTwoAvatar={playerTwo?.avatar || '🐯'}
                    playerOneScore={playerOneState.score}
                    playerTwoScore={playerTwoState.score}
                    showCompetitionBar={showCompetitionBar}
                    showOvertake={showOvertake}
                    smartboardMode={smartboardMode}
                    playerOneContent={
                        <MemoryMatrixPlayerSide
                            state={playerOneState}
                            onAnswer={(cells) => handlePlayerAnswer(PlayerSide.LEFT, cells)}
                            playerColor={playerOne.color}
                        />
                    }
                    playerTwoContent={
                        <MemoryMatrixPlayerSide
                            state={playerTwoState}
                            onAnswer={(cells) => handlePlayerAnswer(PlayerSide.RIGHT, cells)}
                            playerColor={playerTwo?.color || '#3B82F6'}
                        />
                    }
                />
            </div>
        )
    }

    return null
}

interface MemoryMatrixPlayerSideProps {
    state: PlayerGameState
    onAnswer: (selectedCells: Set<number>) => void
    playerColor: string
}

function MemoryMatrixPlayerSide({ state, onAnswer, playerColor }: MemoryMatrixPlayerSideProps) {
    const [phase, setPhase] = useState<'memorize' | 'recall'>('memorize')
    const [selectedCells, setSelectedCells] = useState<Set<number>>(new Set())
    const [showFeedback, setShowFeedback] = useState(false)

    const currentQuestion = state.questions[state.currentIndex] as MemoryMatrixPattern
    if (!currentQuestion) return <div>Loading...</div>

    const { gridSize, pattern, displayTime } = currentQuestion.content

    useEffect(() => {
        setPhase('memorize')
        setSelectedCells(new Set())
        setShowFeedback(false)

        const timer = setTimeout(() => {
            setPhase('recall')
        }, displayTime)

        return () => clearTimeout(timer)
    }, [state.currentIndex, displayTime])

    const handleCellClick = (index: number) => {
        if (phase !== 'recall' || showFeedback) return

        const newSelected = new Set(selectedCells)
        if (newSelected.has(index)) {
            newSelected.delete(index)
        } else {
            newSelected.add(index)
        }
        setSelectedCells(newSelected)
    }

    const handleSubmit = () => {
        if (phase !== 'recall' || showFeedback) return

        setShowFeedback(true)
        onAnswer(selectedCells)

        setTimeout(() => {
            setShowFeedback(false)
            setSelectedCells(new Set())
        }, 2000)
    }

    const progress = ((state.currentIndex + 1) / state.questions.length) * 100

    return (
        <div className="space-y-4">
            <div className="h-3 bg-gray-200 rounded-full overflow-hidden">
                <div
                    className="h-full transition-all duration-300"
                    style={{ width: `${progress}%`, backgroundColor: playerColor }}
                />
            </div>

            <div className="flex justify-between items-center">
                <div className="text-center">
                    <div className="text-2xl font-black" style={{ color: playerColor }}>
                        {state.correct}/{state.questions.length}
                    </div>
                    <div className="text-xs text-gray-600">Correct</div>
                </div>

                <div
                    className="px-3 py-1 rounded-full font-bold text-white text-sm"
                    style={{ backgroundColor: phase === 'memorize' ? '#3B82F6' : '#8B5CF6' }}
                >
                    {phase === 'memorize' ? '👀 MEMORIZE' : '🧠 RECALL'}
                </div>

                <div className="text-center">
                    <div className="text-2xl font-black text-gray-900">
                        {Math.round((state.correct / (state.currentIndex + 1)) * 100)}%
                    </div>
                    <div className="text-xs text-gray-600">Accuracy</div>
                </div>
            </div>

            <div className="flex justify-center">
                <div
                    className="grid gap-2"
                    style={{
                        gridTemplateColumns: `repeat(${gridSize}, minmax(0, 1fr))`,
                        maxWidth: `${gridSize * 60}px`
                    }}
                >
                    {Array.from({ length: gridSize * gridSize }).map((_, index) => {
                        const isInPattern = pattern.includes(index)
                        const isSelected = selectedCells.has(index)
                        const showPattern = phase === 'memorize' || showFeedback

                        return (
                            <button
                                key={index}
                                onClick={() => handleCellClick(index)}
                                disabled={phase === 'memorize'}
                                className={`aspect-square rounded-lg transition-all duration-200 ${showPattern && isInPattern
                                        ? 'bg-purple-500'
                                        : isSelected
                                            ? showFeedback
                                                ? isInPattern
                                                    ? 'bg-green-500'
                                                    : 'bg-red-500'
                                                : 'bg-blue-400'
                                            : 'bg-gray-200 hover:bg-gray-300'
                                    }`}
                                style={{
                                    width: '50px',
                                    height: '50px'
                                }}
                            />
                        )
                    })}
                </div>
            </div>

            {phase === 'recall' && !showFeedback && (
                <button
                    onClick={handleSubmit}
                    className="w-full p-3 text-white font-bold rounded-xl touch-target"
                    style={{ backgroundColor: playerColor }}
                >
                    Submit Answer
                </button>
            )}
        </div>
    )
}

'use client'

import { useState, useEffect, useRef } from 'react'
import toast from 'react-hot-toast'
import { ContentGenerator, SessionMode, SessionManager } from '@/lib/game-engine/content-generator'
import { WorldFlagsContent, FlagQuestion } from '@/lib/game-engine/content-pools/world-flags'
import { ScoringEngine } from '@/lib/game-engine/scoring'
import { FeedbackSystem, getEncouragingMessage } from '@/lib/game-engine/feedback'
import '../../styles/game-animations.css'

interface WorldFlagsProps {
    onGameEnd: (score: number, correctAnswers: number, totalQuestions: number) => void
    studentId?: string
    difficulty?: 1 | 2 | 3 | 4
    mode?: SessionMode
    region?: 'all' | 'asia' | 'europe' | 'africa' | 'americas' | 'oceania'
}

export default function WorldFlags({
    onGameEnd,
    studentId = 'demo',
    difficulty = 2,
    mode = SessionMode.STANDARD,
    region = 'all'
}: WorldFlagsProps) {
    // Game state
    const [questions, setQuestions] = useState<FlagQuestion[]>([])
    const [currentIndex, setCurrentIndex] = useState(0)
    const [selectedAnswer, setSelectedAnswer] = useState<number | null>(null)
    const [showFeedback, setShowFeedback] = useState(false)
    const [showGeoFact, setShowGeoFact] = useState(false)
    const [gameStarted, setGameStarted] = useState(false)

    // Scoring state
    const [score, setScore] = useState(0)
    const [correctAnswers, setCorrectAnswers] = useState(0)
    const [streak, setStreak] = useState(0)
    const [mistakes, setMistakes] = useState(0)

    // Time tracking
    const [timeLeft, setTimeLeft] = useState(0)
    const [questionStartTime, setQuestionStartTime] = useState(Date.now())
    const [totalTimeSpent, setTotalTimeSpent] = useState(0)

    // UI state
    const [showCountdown, setShowCountdown] = useState(true)
    const initializedRef = useRef(false)

    const feedbackSystem = useRef(new FeedbackSystem(true))
    const sessionConfig = SessionManager.getConfig(mode, difficulty)

    // Initialize game
    useEffect(() => {
        if (!initializedRef.current) {
            initializedRef.current = true
            initializeGame()
        }
    }, [])

    const initializeGame = async () => {
        await FeedbackSystem.showCountdown()
        setShowCountdown(false)

        const pool = WorldFlagsContent.generateContentPool()

        // Filter by region if specified
        let filteredPool = pool
        if (region !== 'all') {
            filteredPool = {
                easy: pool.easy.filter(q => (q as FlagQuestion).content.region === region),
                medium: pool.medium.filter(q => (q as FlagQuestion).content.region === region),
                hard: pool.hard.filter(q => (q as FlagQuestion).content.region === region),
                challenge: pool.challenge?.filter(q => (q as FlagQuestion).content.region === region)
            }
        }

        const seed = ContentGenerator.generateSeed(studentId)
        const generator = new ContentGenerator(seed)
        const difficultyMix = ContentGenerator.getDifficultyMix(difficulty)
        const sessionQuestions = generator.generateSession(filteredPool, sessionConfig.questionCount, difficultyMix)

        setQuestions(sessionQuestions as FlagQuestion[])
        setTimeLeft(sessionConfig.timeLimit || 600)
        setQuestionStartTime(Date.now())
        setGameStarted(true)
    }

    // Timer
    useEffect(() => {
        if (!gameStarted || timeLeft <= 0) return

        const timer = setInterval(() => {
            setTimeLeft(prev => {
                if (prev <= 1) {
                    endGame()
                    return 0
                }
                return prev - 1
            })
        }, 1000)

        return () => clearInterval(timer)
    }, [gameStarted, timeLeft])

    // Safety: Ensure game is marked started if questions exist
    useEffect(() => {
        if (questions.length > 0 && !gameStarted && timeLeft > 0) {
            setGameStarted(true)
        }
    }, [questions.length, gameStarted, timeLeft])

    // Lock state
    const isSubmitting = useRef(false)
    const lastAnswerTime = useRef(0)

    const handleAnswer = (answerIndex: number) => {
        console.log('handleAnswer clicked:', answerIndex, 'isSubmitting:', isSubmitting.current, 'gameStarted:', gameStarted)
        const now = Date.now()
        // Debounce (200ms) and Submission Lock
        if (showFeedback || !gameStarted || isSubmitting.current || (now - lastAnswerTime.current < 200)) {
            console.log('handleAnswer blocked. Feedback:', showFeedback, 'Started:', gameStarted, 'Submitting:', isSubmitting.current)
            return
        }

        isSubmitting.current = true
        lastAnswerTime.current = now

        const currentQuestion = questions[currentIndex]
        const isCorrect = answerIndex === currentQuestion.correctAnswer
        const timeSpent = (now - questionStartTime) / 1000

        setSelectedAnswer(answerIndex)
        setShowFeedback(true)
        setTotalTimeSpent(prev => prev + timeSpent)

        if (isCorrect) {
            const newStreak = streak + 1
            setStreak(newStreak)
            setCorrectAnswers(prev => prev + 1)

            const xpResult = ScoringEngine.calculateXP({
                baseScore: currentQuestion.points,
                accuracy: 1,
                timeSpent,
                expectedTime: currentQuestion.timeLimit || 15,
                streak: newStreak,
                hintsUsed: 0,
                mistakes,
                difficulty,
                perfectRound: false
            })

            setScore(prev => prev + xpResult.totalXP)

            feedbackSystem.current.showCorrectAnimation()
            feedbackSystem.current.showXPPopup(xpResult.totalXP)

            const combo = ScoringEngine.getComboLevel(newStreak)
            if (newStreak >= 3) {
                feedbackSystem.current.showComboAnimation(combo.multiplier, newStreak)
            }

            // Show geo-fact on correct answer
            if (currentQuestion.content.geoFact) {
                setShowGeoFact(true)
            }

            toast.success(`${getEncouragingMessage('excellent')} +${xpResult.totalXP} XP`, {
                icon: '🌍',
                duration: 1500
            })
        } else {
            setStreak(0)
            setMistakes(prev => prev + 1)

            feedbackSystem.current.showWrongAnimation()
            toast.error('Not quite! Keep exploring! 🗺️', {
                duration: 1500
            })
        }

        // Move to next question
        setTimeout(() => {
            if (currentIndex < questions.length - 1) {
                setCurrentIndex(prev => prev + 1)
                setSelectedAnswer(null)
                setShowFeedback(false)
                setShowGeoFact(false)
                isSubmitting.current = false // Unlock
                setQuestionStartTime(Date.now())
            } else {
                endGame()
            }
        }, showGeoFact ? 3000 : 1500)
    }

    const endGame = () => {
        setGameStarted(false)

        const accuracy = correctAnswers / questions.length
        if (accuracy >= 0.9) {
            feedbackSystem.current.triggerConfetti('perfect')
        } else if (accuracy >= 0.7) {
            feedbackSystem.current.triggerConfetti('amazing')
        }

        onGameEnd(score, correctAnswers, questions.length)
    }

    if (showCountdown || questions.length === 0) {
        return (
            <div className="flex items-center justify-center h-96">
                <div className="text-center">
                    <div className="text-6xl mb-4 animate-bounce">🌍</div>
                    <div className="text-2xl font-bold text-gray-900">Loading World Flags...</div>
                </div>
            </div>
        )
    }

    const currentQuestion = questions[currentIndex]
    const progress = ((currentIndex + 1) / questions.length) * 100
    const combo = ScoringEngine.getComboLevel(streak)

    // Region colors
    const regionColors = {
        asia: 'bg-red-100 text-red-700',
        europe: 'bg-blue-100 text-blue-700',
        africa: 'bg-yellow-100 text-yellow-700',
        americas: 'bg-green-100 text-green-700',
        oceania: 'bg-purple-100 text-purple-700'
    }

    return (
        <div className="bg-white rounded-2xl shadow-2xl p-8 relative overflow-hidden">
            {/* Background gradient */}
            <div
                className="absolute inset-0 opacity-5 transition-all duration-500 pointer-events-none"
                style={{
                    background: `linear-gradient(135deg, ${combo.color} 0%, transparent 100%)`
                }}
            />

            {/* Progress Bar */}
            <div className="absolute top-0 left-0 right-0 h-2 bg-gray-200">
                <div
                    className="h-full bg-gradient-to-r from-green-500 to-green-600 transition-all duration-300"
                    style={{ width: `${progress}%` }}
                />
            </div>

            {/* Header */}
            <div className="flex items-center justify-between mb-6 mt-2">
                <div className="flex items-center gap-4">
                    {/* Timer */}
                    <div className="flex items-center gap-2">
                        <div className="text-3xl">⏱️</div>
                        <div>
                            <div className={`text-3xl font-bold ${timeLeft < 30 ? 'text-red-500 animate-pulse' : 'text-gray-900'}`}>
                                {Math.floor(timeLeft / 60)}:{(timeLeft % 60).toString().padStart(2, '0')}
                            </div>
                            <div className="text-sm text-gray-600">Time Left</div>
                        </div>
                    </div>

                    {/* Combo Indicator */}
                    {streak >= 3 && (
                        <div
                            id="combo-indicator"
                            className="px-4 py-2 rounded-full font-bold text-white combo-active"
                            style={{ backgroundColor: combo.color }}
                        >
                            {streak}x {combo.label}
                        </div>
                    )}
                </div>

                {/* Score */}
                <div className="text-right">
                    <div className="text-4xl font-bold bg-gradient-to-r from-green-500 to-green-600 bg-clip-text text-transparent">
                        {score}
                    </div>
                    <div className="text-sm text-gray-600">XP</div>
                </div>
            </div>

            {/* Question Card */}
            <div className="bg-gradient-to-br from-gray-50 to-gray-100 rounded-xl p-8 mb-6 question-enter">
                <div className="flex items-center justify-between mb-4">
                    <div className="text-sm font-semibold text-gray-600">
                        Question {currentIndex + 1} of {questions.length}
                    </div>
                    <div className="flex items-center gap-2">
                        <span className={`px-3 py-1 rounded-full text-xs font-bold ${regionColors[currentQuestion.content.region]}`}>
                            {currentQuestion.content.region.toUpperCase()}
                        </span>
                        <span className={`px-3 py-1 rounded-full text-xs font-bold ${currentQuestion.difficulty === 'EASY' ? 'bg-green-100 text-green-700' :
                            currentQuestion.difficulty === 'MEDIUM' ? 'bg-blue-100 text-blue-700' :
                                currentQuestion.difficulty === 'HARD' ? 'bg-purple-100 text-purple-700' :
                                    'bg-red-100 text-red-700'
                            }`}>
                            {currentQuestion.difficulty}
                        </span>
                    </div>
                </div>

                {/* Flag Display & Map */}
                <div className="flex flex-col md:flex-row items-center justify-center gap-8 mb-8">
                    <div className="text-center">
                        <div className="relative w-48 h-32 mb-4 bg-white rounded-lg shadow-lg overflow-hidden border-2 border-gray-100 mx-auto">
                            <img
                                src={currentQuestion.content.flagUrl}
                                alt="Flag"
                                className="w-full h-full object-cover animate-pop"
                            />
                        </div>
                        <div className="text-xl font-bold text-gray-900">
                            {currentQuestion.content.question}
                        </div>
                    </div>

                    {/* Region Map Visualization */}
                    <div className="w-48 h-48 bg-gray-100 rounded-2xl p-4 flex items-center justify-center border-2 border-dashed border-gray-300 relative overflow-hidden group">
                        <svg viewBox="0 0 1000 500" className="w-full h-full opacity-80 group-hover:opacity-100 transition-opacity">
                            {/* Background styling for water/world is handled by parent container, we draw continents here */}

                            {/* Americas (North & South) */}
                            <path
                                d="M150,50 L250,50 L280,150 L250,250 L280,350 L220,450 L150,400 L120,300 L150,200 L100,100 Z"
                                d-real="M 50 60 L 150 40 L 250 80 L 200 150 L 220 220 L 250 300 L 220 450 L 150 420 L 120 300 L 80 200 L 20 100 Z (Simplified approx)"
                                d-rect="M50,50 h200 v400 h-200 z"
                                d-simplified="M 50,60 Q 150,30 250,60 L 200,180 L 240,450 L 180,480 L 140,200 L 20,80 Z"
                                d-final="M165,45 C165,45 285,35 295,95 C305,155 245,185 255,235 C265,285 295,355 265,445 L195,435 C195,435 155,285 135,235 C115,185 55,105 55,105 C55,105 85,55 165,45 Z"
                                fill="currentColor"
                                className={`transition-colors duration-300 ${currentQuestion.content.region === 'americas' ? 'text-green-500 drop-shadow-md' : 'text-gray-300'}`}
                            />

                            {/* Europe */}
                            <path
                                d-final="M435,55 C435,55 535,45 535,115 C535,115 485,145 465,135 C445,125 415,115 435,55 Z"
                                fill="currentColor"
                                className={`transition-colors duration-300 ${currentQuestion.content.region === 'europe' ? 'text-blue-500 drop-shadow-md' : 'text-gray-300'}`}
                            />

                            {/* Africa */}
                            <path
                                d-final="M435,155 C435,155 535,155 565,205 C595,255 565,395 495,395 C425,395 395,255 425,195 C455,135 435,155 435,155 Z"
                                fill="currentColor"
                                className={`transition-colors duration-300 ${currentQuestion.content.region === 'africa' ? 'text-yellow-500 drop-shadow-md' : 'text-gray-300'}`}
                            />

                            {/* Asia */}
                            <path
                                d-final="M555,55 C555,55 855,55 895,155 C935,255 815,295 735,275 C655,255 555,135 555,55 Z"
                                fill="currentColor"
                                className={`transition-colors duration-300 ${currentQuestion.content.region === 'asia' ? 'text-red-500 drop-shadow-md' : 'text-gray-300'}`}
                            />

                            {/* Oceania */}
                            <path
                                d-final="M755,305 C755,305 895,295 915,365 C935,435 835,455 795,425 C755,395 725,355 755,305 Z"
                                fill="currentColor"
                                className={`transition-colors duration-300 ${currentQuestion.content.region === 'oceania' ? 'text-purple-500 drop-shadow-md' : 'text-gray-300'}`}
                            />
                        </svg>
                        <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                            <span className="text-xs font-bold text-gray-500 bg-white/90 px-3 py-1 rounded-full uppercase tracking-widest shadow-sm">
                                {currentQuestion.content.region} Region
                            </span>
                        </div>
                    </div>
                </div>

                {/* Answer Options - Large Touch Targets */}
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4 relative z-10">
                    {currentQuestion.options.map((option, index) => (
                        <button
                            key={index}
                            onClick={() => handleAnswer(index)}
                            disabled={showFeedback}
                            className={`min-h-[80px] p-6 text-xl font-bold rounded-2xl transition-all duration-200 shadow-sm border-4 touch-manipulation select-none active:scale-95 ${showFeedback
                                ? index === currentQuestion.correctAnswer
                                    ? 'bg-emerald-500 text-white border-emerald-600 scale-105 z-10'
                                    : index === selectedAnswer
                                        ? 'bg-red-500 text-white border-red-600 animate-wrong-shake'
                                        : 'bg-gray-100 text-gray-400 border-gray-200'
                                : 'bg-white border-gray-100 hover:border-emerald-500 hover:bg-emerald-50 text-gray-900'
                                }`}
                        >
                            {option}
                        </button>
                    ))}
                </div>

                {/* Geo-Fact */}
                {showGeoFact && currentQuestion.content.geoFact && (
                    <div className="mt-4 p-4 bg-green-50 border-2 border-green-200 rounded-lg slide-up">
                        <div className="flex items-start gap-2">
                            <span className="text-2xl">🌍</span>
                            <div>
                                <div className="font-bold text-green-900 mb-1">Did you know?</div>
                                <div className="text-green-800">{currentQuestion.content.geoFact}</div>
                                {currentQuestion.content.capital && (
                                    <div className="text-sm text-green-700 mt-1">
                                        Capital: <span className="font-semibold">{currentQuestion.content.capital}</span>
                                    </div>
                                )}
                            </div>
                        </div>
                    </div>
                )}
            </div>

            {/* Stats Footer */}
            <div className="flex items-center justify-center gap-8 text-sm">
                <div className="flex items-center gap-2">
                    <span className="text-2xl">✅</span>
                    <div>
                        <div className="font-bold text-gray-900">{correctAnswers}</div>
                        <div className="text-gray-600">Correct</div>
                    </div>
                </div>

                <div className="flex items-center gap-2">
                    <span className="text-2xl">🎯</span>
                    <div>
                        <div className="font-bold text-gray-900">
                            {questions.length > 0 ? Math.round((correctAnswers / (currentIndex + 1)) * 100) : 0}%
                        </div>
                        <div className="text-gray-600">Accuracy</div>
                    </div>
                </div>

                <div className="flex items-center gap-2">
                    <span className="text-2xl">🔥</span>
                    <div>
                        <div className="font-bold text-gray-900">{streak}</div>
                        <div className="text-gray-600">Streak</div>
                    </div>
                </div>

                <div className="flex items-center gap-2">
                    <span className="text-2xl">⚡</span>
                    <div>
                        <div className="font-bold text-gray-900">{combo.multiplier}x</div>
                        <div className="text-gray-600">Multiplier</div>
                    </div>
                </div>
            </div>
        </div>
    )
}

'use client'

/**
 * World Flags - Multiplayer Edition
 * Competitive geography quiz with speed bonuses
 */

import { useState, useEffect, useRef } from 'react'
import { GameMode, PlayerSide } from '@/lib/multiplayer/game-modes'
import { PlayerSetupManager } from '@/lib/multiplayer/player-setup'
import { SplitScreenEngine, PlayerGameState } from '@/lib/multiplayer/split-screen'
import { CompetitionEngine } from '@/lib/multiplayer/competition'
import { soundManager } from '@/lib/multiplayer/sounds'
import PlayerSetupLobby from '@/components/multiplayer/PlayerSetupLobby'
import SplitScreenLayout from '@/components/multiplayer/SplitScreenLayout'
import VictoryScreen from '@/components/multiplayer/VictoryScreen'
import Countdown from '@/components/multiplayer/Countdown'
import SmartboardControls from '@/components/multiplayer/SmartboardControls'
import { WorldFlagsContent, FlagQuestion } from '@/lib/game-engine/content-pools/world-flags'
import { ScoringEngine } from '@/lib/game-engine/scoring'
import Image from 'next/image'

enum GameState {
    SETUP = 'setup',
    COUNTDOWN = 'countdown',
    PLAYING = 'playing',
    VICTORY = 'victory'
}

export default function WorldFlagsMultiplayer() {
    const [gameState, setGameState] = useState<GameState>(GameState.SETUP)
    const [setupManager, setSetupManager] = useState<PlayerSetupManager | null>(null)
    const [splitScreenEngine] = useState(() => new SplitScreenEngine())
    const [competitionEngine] = useState(() => new CompetitionEngine())

    const [playerOneState, setPlayerOneState] = useState<PlayerGameState | null>(null)
    const [playerTwoState, setPlayerTwoState] = useState<PlayerGameState | null>(null)
    const [showOvertake, setShowOvertake] = useState(false)

    const [smartboardMode, setSmartboardMode] = useState(false)
    const [touchOptimized, setTouchOptimized] = useState(true)
    const [soundEffects, setSoundEffects] = useState(true)
    const [showCompetitionBar, setShowCompetitionBar] = useState(true)

    useEffect(() => {
        soundManager.setEnabled(soundEffects)
    }, [soundEffects])

    const handleStartGame = (manager: PlayerSetupManager) => {
        setSetupManager(manager)
        setGameState(GameState.COUNTDOWN)
    }

    const handleCountdownComplete = () => {
        initializeMultiplayerGame()
        setGameState(GameState.PLAYING)
    }

    const initializeMultiplayerGame = () => {
        if (!setupManager) return

        const pool = WorldFlagsContent.generateContentPool()
        const seed1 = Date.now()
        const seed2 = Date.now() + 1000

        const { playerOne: p1Questions, playerTwo: p2Questions } = splitScreenEngine.generateIndependentQuestions(
            pool,
            20, // 20 flags per player
            seed1,
            seed2
        )

        splitScreenEngine.initializeGame(p1Questions, p2Questions, 120) // 2 minutes
        splitScreenEngine.startTimer(
            (timeLeft) => {
                const p1 = splitScreenEngine.getPlayerState(PlayerSide.LEFT)
                const p2 = splitScreenEngine.getPlayerState(PlayerSide.RIGHT)
                setPlayerOneState({ ...p1, timeRemaining: timeLeft })
                setPlayerTwoState({ ...p2, timeRemaining: timeLeft })
            },
            () => endGame()
        )

        setPlayerOneState(splitScreenEngine.getPlayerState(PlayerSide.LEFT))
        setPlayerTwoState(splitScreenEngine.getPlayerState(PlayerSide.RIGHT))
    }

    const handlePlayerAnswer = (side: PlayerSide, answer: string, reactionTime: number) => {
        const state = splitScreenEngine.getPlayerState(side)
        const currentQuestion = state.questions[state.currentIndex] as FlagQuestion
        const isCorrect = answer === currentQuestion.options[currentQuestion.correctAnswer]

        let points = currentQuestion.points

        // Speed bonus for fast answers (<3s = 2x)
        if (isCorrect && reactionTime < 3000) {
            points *= 2
            soundManager.playSpeedBonus()
        }

        splitScreenEngine.handleAnswer(side, isCorrect, points)

        const p1State = splitScreenEngine.getPlayerState(PlayerSide.LEFT)
        const p2State = splitScreenEngine.getPlayerState(PlayerSide.RIGHT)

        const overtake = competitionEngine.updateScores(p1State.score, p2State.score)

        if (overtake) {
            setShowOvertake(true)
            soundManager.playOvertake()
            setTimeout(() => setShowOvertake(false), 2000)
        }

        if (isCorrect) {
            soundManager.playCorrect()
            if (state.streak >= 3) {
                soundManager.playCombo(state.combo)
            }
        } else {
            soundManager.playWrong()
        }

        setPlayerOneState(splitScreenEngine.getPlayerState(PlayerSide.LEFT))
        setPlayerTwoState(splitScreenEngine.getPlayerState(PlayerSide.RIGHT))

        if (splitScreenEngine.isGameOver()) {
            setTimeout(() => endGame(), 1000)
        }
    }

    const endGame = () => {
        splitScreenEngine.stopTimer()
        setGameState(GameState.VICTORY)
    }

    const handlePlayAgain = () => {
        competitionEngine.reset()
        splitScreenEngine.reset()
        setGameState(GameState.COUNTDOWN)
    }

    const handleSwitchSides = () => {
        setupManager?.switchSides()
        handlePlayAgain()
    }

    const handleNewPlayers = () => {
        competitionEngine.reset()
        splitScreenEngine.reset()
        setGameState(GameState.SETUP)
    }

    const handleBackToMenu = () => {
        window.location.href = '/dashboard/student/games'
    }

    const toggleFullscreen = () => {
        if (!document.fullscreenElement) {
            document.documentElement.requestFullscreen()
        } else {
            document.exitFullscreen()
        }
    }

    if (gameState === GameState.SETUP) {
        return <PlayerSetupLobby onStartGame={handleStartGame} gameName="World Flags Race" />
    }

    if (gameState === GameState.COUNTDOWN) {
        return <Countdown onComplete={handleCountdownComplete} duration={3} />
    }

    if (gameState === GameState.VICTORY && setupManager && playerOneState && playerTwoState) {
        const winner = splitScreenEngine.getWinner()
        const stats = splitScreenEngine.getFinalStats()
        const { playerOne, playerTwo } = setupManager.getPlayers()

        return (
            <VictoryScreen
                winner={winner}
                playerOneName={playerOne.name}
                playerTwoName={playerTwo?.name || 'Player 2'}
                playerOneScore={stats.playerOne.score}
                playerTwoScore={stats.playerTwo.score}
                playerOneAccuracy={stats.playerOne.accuracy}
                playerTwoAccuracy={stats.playerTwo.accuracy}
                onPlayAgain={handlePlayAgain}
                onSwitchSides={handleSwitchSides}
                onNewPlayers={handleNewPlayers}
                onBackToMenu={handleBackToMenu}
            />
        )
    }

    if (gameState === GameState.PLAYING && setupManager && playerOneState && playerTwoState) {
        const { playerOne, playerTwo } = setupManager.getPlayers()

        return (
            <div className={smartboardMode ? 'smartboard-mode' : ''}>
                <SmartboardControls
                    smartboardMode={smartboardMode}
                    touchOptimized={touchOptimized}
                    soundEffects={soundEffects}
                    showCompetitionBar={showCompetitionBar}
                    onToggleSmartboard={setSmartboardMode}
                    onToggleTouch={setTouchOptimized}
                    onToggleSounds={setSoundEffects}
                    onToggleCompetitionBar={setShowCompetitionBar}
                    onToggleFullscreen={toggleFullscreen}
                />

                <SplitScreenLayout
                    playerOneName={playerOne.name}
                    playerTwoName={playerTwo?.name || 'Player 2'}
                    playerOneColor={playerOne.color}
                    playerTwoColor={playerTwo?.color || '#3B82F6'}
                    playerOneAvatar={playerOne.avatar}
                    playerTwoAvatar={playerTwo?.avatar || '🐯'}
                    playerOneScore={playerOneState.score}
                    playerTwoScore={playerTwoState.score}
                    showCompetitionBar={showCompetitionBar}
                    showOvertake={showOvertake}
                    smartboardMode={smartboardMode}
                    playerOneContent={
                        <WorldFlagsPlayerSide
                            state={playerOneState}
                            onAnswer={(answer, time) => handlePlayerAnswer(PlayerSide.LEFT, answer, time)}
                            playerColor={playerOne.color}
                        />
                    }
                    playerTwoContent={
                        <WorldFlagsPlayerSide
                            state={playerTwoState}
                            onAnswer={(answer, time) => handlePlayerAnswer(PlayerSide.RIGHT, answer, time)}
                            playerColor={playerTwo?.color || '#3B82F6'}
                        />
                    }
                />
            </div>
        )
    }

    return null
}

interface WorldFlagsPlayerSideProps {
    state: PlayerGameState
    onAnswer: (answer: string, reactionTime: number) => void
    playerColor: string
}

function WorldFlagsPlayerSide({ state, onAnswer, playerColor }: WorldFlagsPlayerSideProps) {
    const [selectedAnswer, setSelectedAnswer] = useState<string | null>(null)
    const [showFeedback, setShowFeedback] = useState(false)
    const [questionStartTime, setQuestionStartTime] = useState(Date.now())
    const isSubmitting = useRef(false) // Lock

    useEffect(() => {
        setQuestionStartTime(Date.now())
    }, [state.currentIndex])

    const currentQuestion = state.questions[state.currentIndex] as FlagQuestion
    if (!currentQuestion) return <div>Loading...</div>

    const handleAnswer = (answer: string, e: React.PointerEvent) => {
        e.preventDefault()
        e.stopPropagation()

        if (showFeedback || isSubmitting.current) return
        isSubmitting.current = true

        const reactionTime = Date.now() - questionStartTime
        setSelectedAnswer(answer)
        setShowFeedback(true)
        onAnswer(answer, reactionTime)

        setTimeout(() => {
            setSelectedAnswer(null)
            setShowFeedback(false)
            isSubmitting.current = false
        }, 1200)
    }

    const progress = ((state.currentIndex + 1) / state.questions.length) * 100
    const combo = ScoringEngine.getComboLevel(state.streak)

    return (
        <div className="space-y-6 select-none touch-none">
            {/* Progress */}
            <div className="h-3 bg-gray-200 rounded-full overflow-hidden">
                <div
                    className="h-full transition-all duration-300"
                    style={{ width: `${progress}%`, backgroundColor: playerColor }}
                />
            </div>

            {/* Stats */}
            <div className="flex justify-between items-center">
                <div className="text-center">
                    <div className="text-3xl font-black" style={{ color: playerColor }}>
                        {state.correct}/{state.questions.length}
                    </div>
                    <div className="text-sm text-gray-600">Correct</div>
                </div>

                {state.streak >= 3 && (
                    <div
                        className="px-4 py-2 rounded-full font-bold text-white animate-pulse"
                        style={{ backgroundColor: combo.color }}
                    >
                        🌍 {state.streak}x Streak!
                    </div>
                )}

                <div className="text-center">
                    <div className="text-3xl font-black text-gray-900">
                        ⚡ {combo.multiplier}x
                    </div>
                    <div className="text-sm text-gray-600">Speed</div>
                </div>
            </div>

            {/* Flag Image & Map */}
            <div className="bg-white rounded-xl p-4 shadow-xl">
                <div className="text-xs text-gray-500 mb-2 text-center uppercase tracking-wider font-bold">
                    Question {state.currentIndex + 1}
                </div>

                <div className="flex flex-col gap-4">
                    <div className="relative w-full aspect-[3/2] rounded-lg overflow-hidden border-2 border-gray-100 shadow-inner">
                        <img
                            src={currentQuestion.content.flagUrl}
                            alt="Flag"
                            className="w-full h-full object-cover animate-pop"
                        />
                    </div>

                    {/* Region Map Visualization */}
                    <div className="h-24 bg-gray-50 rounded-lg flex items-center justify-center border border-dashed border-gray-200 relative overflow-hidden group">
                        <svg viewBox="0 0 100 100" className="h-16 opacity-30 group-hover:opacity-50 transition-opacity">
                            {currentQuestion.content.region === 'asia' && <path d="M10,10 Q50,0 90,10 T90,90 T10,90 Z" fill="currentColor" className="text-red-500" />}
                            {currentQuestion.content.region === 'europe' && <path d="M20,20 Q40,10 60,20 T80,40 T60,60 T20,40 Z" fill="currentColor" className="text-blue-500" />}
                            {currentQuestion.content.region === 'africa' && <path d="M30,10 Q60,10 70,40 T60,80 T30,80 T20,40 Z" fill="currentColor" className="text-yellow-600" />}
                            {currentQuestion.content.region === 'americas' && <path d="M40,5 Q60,5 60,40 T50,95 T30,80 T20,40 Z" fill="currentColor" className="text-green-600" />}
                            {currentQuestion.content.region === 'oceania' && <path d="M70,70 Q80,65 90,75 T80,90 T70,85 Z" fill="currentColor" className="text-purple-500" />}
                        </svg>
                        <div className="absolute inset-0 flex items-center justify-center">
                            <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest bg-white/60 px-2 py-0.5 rounded-full">
                                {currentQuestion.content.region}
                            </span>
                        </div>
                    </div>
                </div>

                <div className="text-lg font-bold text-center text-gray-900 mt-4 leading-tight">
                    Which country is this?
                </div>
            </div>

            {/* Answer Options */}
            <div className="grid grid-cols-2 gap-3">
                {currentQuestion.options.map((option, index) => (
                    <button
                        key={index}
                        onPointerDown={(e) => handleAnswer(option, e)}
                        disabled={showFeedback}
                        className={`p-4 text-lg font-bold rounded-xl transition-all touch-target select-none ${showFeedback
                            ? option === currentQuestion.options[currentQuestion.correctAnswer]
                                ? 'bg-green-500 text-white scale-105 z-10'
                                : option === selectedAnswer
                                    ? 'bg-red-500 text-white animate-wrong-shake'
                                    : 'bg-gray-100 text-gray-400'
                            : 'bg-white border-4 hover:scale-105 text-gray-900 active:scale-95'
                            }`}
                        style={{
                            borderColor: showFeedback ? 'transparent' : playerColor,
                            touchAction: 'none'
                        }}
                    >
                        {option}
                    </button>
                ))}
            </div>

            {/* Speed Bonus Indicator */}
            <div className="text-center text-sm text-gray-600">
                💨 Answer in &lt;3s for 2x points!
            </div>
        </div>
    )
}

'use client'

import { useState, useEffect } from 'react'
import toast from 'react-hot-toast'
import { motion, AnimatePresence } from 'framer-motion'

interface ApiKey {
    id: string
    name: string
    permissions: string[]
    rateLimit: number
    isActive: boolean
    lastUsedAt: string | null
    expiresAt: string | null
    createdAt: string
}

export default function ApiKeyManagement() {
    const [apiKeys, setApiKeys] = useState<ApiKey[]>([])
    const [loading, setLoading] = useState(true)
    const [showCreateModal, setShowCreateModal] = useState(false)
    const [newKeyName, setNewKeyName] = useState('')
    const [newKeyPermissions, setNewKeyPermissions] = useState(['read'])
    const [generatedKey, setGeneratedKey] = useState<string | null>(null)

    useEffect(() => {
        fetchApiKeys()
    }, [])

    const fetchApiKeys = async () => {
        try {
            const response = await fetch('/api/settings/api-keys')
            const data = await response.json()
            setApiKeys(data.apiKeys || [])
        } catch (error) {
            toast.error('Failed to load API keys')
        } finally {
            setLoading(false)
        }
    }

    const handleCreateKey = async () => {
        if (!newKeyName.trim()) {
            toast.error('Please enter a name for the API key')
            return
        }

        try {
            const response = await fetch('/api/settings/api-keys', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    name: newKeyName,
                    permissions: newKeyPermissions
                })
            })

            const data = await response.json()

            if (data.success) {
                setGeneratedKey(data.apiKey)
                setNewKeyName('')
                setNewKeyPermissions(['read'])
                fetchApiKeys()
                toast.success('API key generated successfully!')
            } else {
                toast.error(data.error || 'Failed to generate API key')
            }
        } catch (error) {
            toast.error('Failed to generate API key')
        }
    }

    const handleDeleteKey = async (keyId: string) => {
        if (!confirm('Are you sure you want to revoke this API key? This action cannot be undone.')) {
            return
        }

        try {
            const response = await fetch(`/api/settings/api-keys/${keyId}`, {
                method: 'DELETE'
            })

            if (response.ok) {
                toast.success('API key revoked successfully')
                fetchApiKeys()
            } else {
                toast.error('Failed to revoke API key')
            }
        } catch (error) {
            toast.error('Failed to revoke API key')
        }
    }

    const copyToClipboard = (text: string) => {
        navigator.clipboard.writeText(text)
        toast.success('Copied to clipboard!')
    }

    if (loading) {
        return <div className="text-center py-12">Loading...</div>
    }

    return (
        <div className="max-w-4xl mx-auto p-6">
            <div className="flex items-center justify-between mb-8">
                <div>
                    <h1 className="text-3xl font-bold text-gray-900">API Keys</h1>
                    <p className="text-gray-600 mt-2">Manage API keys for integrating with EduPlay Pro</p>
                </div>
                <button
                    onClick={() => setShowCreateModal(true)}
                    className="px-6 py-3 bg-emerald-600 text-white rounded-lg font-semibold hover:bg-emerald-700 transition"
                >
                    + Generate New Key
                </button>
            </div>

            {/* API Keys List */}
            <div className="space-y-4">
                {apiKeys.length === 0 ? (
                    <div className="bg-gray-50 rounded-xl p-12 text-center">
                        <div className="text-6xl mb-4">🔑</div>
                        <h3 className="text-xl font-bold text-gray-900 mb-2">No API Keys Yet</h3>
                        <p className="text-gray-600 mb-6">Generate your first API key to start integrating with EduPlay Pro</p>
                        <button
                            onClick={() => setShowCreateModal(true)}
                            className="px-6 py-3 bg-emerald-600 text-white rounded-lg font-semibold hover:bg-emerald-700 transition"
                        >
                            Generate API Key
                        </button>
                    </div>
                ) : (
                    apiKeys.map(key => (
                        <div key={key.id} className="bg-white border-2 border-gray-200 rounded-xl p-6">
                            <div className="flex items-start justify-between">
                                <div className="flex-1">
                                    <div className="flex items-center gap-3 mb-2">
                                        <h3 className="text-lg font-bold text-gray-900">{key.name}</h3>
                                        <span className={`px-3 py-1 rounded-full text-xs font-semibold ${key.isActive ? 'bg-green-100 text-green-700' : 'bg-gray-100 text-gray-700'
                                            }`}>
                                            {key.isActive ? 'Active' : 'Inactive'}
                                        </span>
                                    </div>
                                    <div className="text-sm text-gray-600 space-y-1">
                                        <p><strong>Permissions:</strong> {key.permissions.join(', ')}</p>
                                        <p><strong>Rate Limit:</strong> {key.rateLimit} requests/hour</p>
                                        <p><strong>Created:</strong> {new Date(key.createdAt).toLocaleDateString()}</p>
                                        {key.lastUsedAt && (
                                            <p><strong>Last Used:</strong> {new Date(key.lastUsedAt).toLocaleDateString()}</p>
                                        )}
                                        {key.expiresAt && (
                                            <p><strong>Expires:</strong> {new Date(key.expiresAt).toLocaleDateString()}</p>
                                        )}
                                    </div>
                                </div>
                                <button
                                    onClick={() => handleDeleteKey(key.id)}
                                    className="px-4 py-2 bg-red-50 text-red-600 rounded-lg font-semibold hover:bg-red-100 transition"
                                >
                                    Revoke
                                </button>
                            </div>
                        </div>
                    ))
                )}
            </div>

            {/* Create Modal */}
            <AnimatePresence>
                {showCreateModal && (
                    <motion.div
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        exit={{ opacity: 0 }}
                        className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4"
                        onClick={() => !generatedKey && setShowCreateModal(false)}
                    >
                        <motion.div
                            initial={{ scale: 0.9 }}
                            animate={{ scale: 1 }}
                            exit={{ scale: 0.9 }}
                            className="bg-white rounded-2xl p-8 max-w-md w-full"
                            onClick={e => e.stopPropagation()}
                        >
                            {!generatedKey ? (
                                <>
                                    <h2 className="text-2xl font-bold text-gray-900 mb-6">Generate API Key</h2>

                                    <div className="mb-6">
                                        <label className="block text-sm font-semibold text-gray-700 mb-2">
                                            Key Name
                                        </label>
                                        <input
                                            type="text"
                                            value={newKeyName}
                                            onChange={e => setNewKeyName(e.target.value)}
                                            placeholder="e.g., Production API Key"
                                            className="w-full px-4 py-3 border-2 border-gray-200 rounded-lg focus:border-emerald-500 focus:outline-none"
                                        />
                                    </div>

                                    <div className="mb-6">
                                        <label className="block text-sm font-semibold text-gray-700 mb-2">
                                            Permissions
                                        </label>
                                        <div className="space-y-2">
                                            {['read', 'write', 'admin'].map(perm => (
                                                <label key={perm} className="flex items-center gap-2">
                                                    <input
                                                        type="checkbox"
                                                        checked={newKeyPermissions.includes(perm)}
                                                        onChange={e => {
                                                            if (e.target.checked) {
                                                                setNewKeyPermissions([...newKeyPermissions, perm])
                                                            } else {
                                                                setNewKeyPermissions(newKeyPermissions.filter(p => p !== perm))
                                                            }
                                                        }}
                                                        className="w-4 h-4"
                                                    />
                                                    <span className="text-gray-700 capitalize">{perm}</span>
                                                </label>
                                            ))}
                                        </div>
                                    </div>

                                    <div className="flex gap-3">
                                        <button
                                            onClick={() => setShowCreateModal(false)}
                                            className="flex-1 px-6 py-3 bg-gray-100 text-gray-700 rounded-lg font-semibold hover:bg-gray-200 transition"
                                        >
                                            Cancel
                                        </button>
                                        <button
                                            onClick={handleCreateKey}
                                            className="flex-1 px-6 py-3 bg-emerald-600 text-white rounded-lg font-semibold hover:bg-emerald-700 transition"
                                        >
                                            Generate
                                        </button>
                                    </div>
                                </>
                            ) : (
                                <>
                                    <h2 className="text-2xl font-bold text-gray-900 mb-4">API Key Generated!</h2>

                                    <div className="bg-yellow-50 border-2 border-yellow-200 rounded-lg p-4 mb-6">
                                        <p className="text-sm text-yellow-800 font-semibold mb-2">⚠️ Important</p>
                                        <p className="text-sm text-yellow-700">
                                            This is the only time you'll see this key. Copy it now and store it securely.
                                        </p>
                                    </div>

                                    <div className="bg-gray-50 rounded-lg p-4 mb-6">
                                        <div className="flex items-center justify-between gap-2">
                                            <code className="text-sm font-mono text-gray-900 break-all">{generatedKey}</code>
                                            <button
                                                onClick={() => copyToClipboard(generatedKey)}
                                                className="px-3 py-2 bg-emerald-600 text-white rounded-lg text-sm font-semibold hover:bg-emerald-700 transition whitespace-nowrap"
                                            >
                                                Copy
                                            </button>
                                        </div>
                                    </div>

                                    <button
                                        onClick={() => {
                                            setGeneratedKey(null)
                                            setShowCreateModal(false)
                                        }}
                                        className="w-full px-6 py-3 bg-emerald-600 text-white rounded-lg font-semibold hover:bg-emerald-700 transition"
                                    >
                                        Done
                                    </button>
                                </>
                            )}
                        </motion.div>
                    </motion.div>
                )}
            </AnimatePresence>

            {/* Documentation Link */}
            <div className="mt-8 bg-blue-50 border-2 border-blue-200 rounded-xl p-6">
                <h3 className="font-bold text-blue-900 mb-2">📚 API Documentation</h3>
                <p className="text-blue-800 mb-4">
                    Learn how to use the EduPlay Pro API to integrate with your applications.
                </p>
                <a
                    href="/docs/api"
                    target="_blank"
                    className="inline-block px-6 py-2 bg-blue-600 text-white rounded-lg font-semibold hover:bg-blue-700 transition"
                >
                    View API Docs →
                </a>
            </div>
        </div>
    )
}
